    private final List<String> erroresSintacticos = new ArrayList<>();
    public Symbol ultimoError = null;

    public List<String> getErroresSintacticos(){
        return erroresSintacticos;
    }

    private int linea(Symbol s) {
        return s == null ? -1 : s.left + 1;
    }

    private int columna(Symbol s) {
        return s == null ? -1 : s.right + 1;
    }

    private String ubicacion(Symbol s) {
        if (s == null) return "fin de entrada";
        return "línea " + linea(s) + ", columna " + columna(s);
    }

    @Override
    public void report_error(String message, Object info) {
        if (info instanceof Symbol) {
            Symbol s = (Symbol) info;
            ultimoError = s;
            erroresSintacticos.add(
                "Error sintáctico en " + ubicacion(s) + ": " + message
            );
        } else {
            erroresSintacticos.add("Error sintáctico: " + message);
        }
    }

    @Override
    public void syntax_error(Symbol cur_token) {
        ultimoError = cur_token;
        if (cur_token != null) {
            erroresSintacticos.add(
                "Token inesperado en " + ubicacion(cur_token)
            );
        } else {
            erroresSintacticos.add("Error sintáctico: fin de entrada inesperado");
        }
    }

    @Override
    public void unrecovered_syntax_error(Symbol cur_token) throws Exception {
        ultimoError = cur_token;
        if (cur_token != null) {
            erroresSintacticos.add(
                "No se pudo recuperar del error en " + ubicacion(cur_token)
            );
        } else {
            erroresSintacticos.add(
                "No se pudo recuperar del error al final de la entrada"
            );
        }
        throw new Exception("Error sintáctico: " + (ultimoError.left + 1) + ":" + (ultimoError.right + 1));
    }


